value => {
  const $anchor = document.createElement('a')
  $anchor.href = value

  // We need to add the anchor to the document to make sure the
  // `pathname` is correctly detected in any browser
  document.body.appendChild($anchor)

  const result = ['hash', 'host', 'hostname', 'pathname', 'port', 'protocol', 'search'].reduce(
    (result, prop) => {
      result[prop] = $anchor[prop] || null
      return result
    },
    {}
  )

  // Make sure to remove the anchor from document as soon as possible
  document.body.removeChild($anchor)

  // Normalize port
  if (!result.port && result.protocol) {
    if (result.protocol === 'https:') {
      result.port = '443'
    }
    if (result.protocol === 'http:') {
      result.port = '80'
    }
  }

  // Return early for browsers that resolved a non-existing `hostname` correctly
  if (result.hostname) {
    return result
  }

  // Handle relative URL's
  if (value.charAt(0) === '/') {
    return parseUrl(window.location.origin + value)
  }

  // Handle all other URL's
  let baseUrl = window.location.href
  baseUrl = baseUrl.substring(0, baseUrl.lastIndexOf('/'))

  return parseUrl(`${baseUrl}/${value}`)
}

focusHandler(event) {
  // If focus leaves modal content, bring it back
  const content = this.$refs.content
  const { target } = event
  if (
    this.noEnforceFocus ||
    !this.isTop ||
    !this.isVisible ||
    !content ||
    document === target ||
    contains(content, target) ||
    (this.computeIgnoreEnforceFocusSelector &&
      closest(this.computeIgnoreEnforceFocusSelector, target, true))
  ) {
    return
  }
  const tabables = getTabables(this.$refs.content)
  const bottomTrap = this.$refs['bottom-trap']
  const topTrap = this.$refs['top-trap']
  if (bottomTrap && target === bottomTrap) {
    // If user pressed TAB out of modal into our bottom trab trap element
    // Find the first tabable element in the modal content and focus it
    if (attemptFocus(tabables[0])) {
      // Focus was successful
      return
    }
  } else if (topTrap && target === topTrap) {
    // If user pressed CTRL-TAB out of modal and into our top tab trap element
    // Find the last tabable element in the modal content and focus it
    if (attemptFocus(tabables[tabables.length - 1])) {
      // Focus was successful
      return
    }
  }
  // Otherwise focus the modal content container
  attemptFocus(content, { preventScroll: true })
}

onClick(event, pageNumber) {
  // Dont do anything if clicking the current active page
  if (pageNumber === this.currentPage) {
    return
  }

  const target = event.currentTarget || event.target

  // Emit a user-cancelable `page-click` event
  const clickEvent = new BvEvent(EVENT_NAME_PAGE_CLICK, {
    cancelable: true,
    vueTarget: this,
    target
  })
  this.$emit(clickEvent.type, clickEvent, pageNumber)
  if (clickEvent.defaultPrevented) {
    return
  }

  // Update the `v-model`
  // Done in in requestAF() to allow browser to complete the
  // native browser click handling of a link
  requestAF(() => {
    this.currentPage = pageNumber
    this.$emit(EVENT_NAME_CHANGE, pageNumber)
  })

  // Emulate native link click page reloading behaviour by blurring the
  // paginator and returning focus to the document
  // Done in a `nextTick()` to ensure rendering complete
  this.$nextTick(() => {
    attemptBlur(target)
  })
}

(row, ignoreFields, includeFields, fieldsObj = {}) => {
  // We first need to format the row based on the field configurations
  // This ensures that we add formatted values for keys that may not
  // exist in the row itself
  const formattedRow = keys(fieldsObj).reduce((result, key) => {
    const field = fieldsObj[key]
    const { filterByFormatted } = field
    const formatter = isFunction(filterByFormatted)
      ? /* istanbul ignore next */ filterByFormatted
      : filterByFormatted
        ? /* istanbul ignore next */ field.formatter
        : null

    if (isFunction(formatter)) {
      result[key] = formatter(row[key], key, row)
    }

    return result
  }, clone(row))

  // Determine the allowed keys:
  //   - Ignore special fields that start with `_`
  //   - Ignore fields in the `ignoreFields` array
  //   - Include only fields in the `includeFields` array
  const allowedKeys = keys(formattedRow).filter(
    key =>
      !IGNORED_FIELD_KEYS[key] &&
      !(isArray(ignoreFields) && ignoreFields.length > 0 && arrayIncludes(ignoreFields, key)) &&
      !(isArray(includeFields) && includeFields.length > 0 && !arrayIncludes(includeFields, key))
  )

  return pick(formattedRow, allowedKeys)
}

updateTabs() {
  const $tabs = this.getTabs()

  // Find last active non-disabled tab in current tabs
  // We trust tab state over `currentTab`, in case tabs were added/removed/re-ordered
  let tabIndex = $tabs.indexOf(
    $tabs
      .slice()
      .reverse()
      .find($tab => $tab.localActive && !$tab.disabled)
  )

  // Else try setting to `currentTab`
  if (tabIndex < 0) {
    const { currentTab } = this
    if (currentTab >= $tabs.length) {
      // Handle last tab being removed, so find the last non-disabled tab
      tabIndex = $tabs.indexOf(
        $tabs
          .slice()
          .reverse()
          .find(notDisabled)
      )
    } else if ($tabs[currentTab] && !$tabs[currentTab].disabled) {
      // Current tab is not disabled
      tabIndex = currentTab
    }
  }

  // Else find first non-disabled tab in current tabs
  if (tabIndex < 0) {
    tabIndex = $tabs.indexOf($tabs.find(notDisabled))
  }

  // Ensure only one tab is active at a time
  $tabs.forEach(($tab, index) => {
    $tab.localActive = index === tabIndex
  })

  this.tabs = $tabs
  this.currentTab = tabIndex
}

bindings => /* istanbul ignore next: not easy to test */ {
  const config = {}

  // If argument, assume element ID
  if (bindings.arg) {
    // Element ID specified as arg
    // We must prepend '#' to become a CSS selector
    config.element = `#${bindings.arg}`
  }

  // Process modifiers
  keys(bindings.modifiers).forEach(mod => {
    if (onlyDigitsRE.test(mod)) {
      // Offset value
      config.offset = toInteger(mod, 0)
    } else if (offsetRE.test(mod)) {
      // Offset method
      config.method = mod
    }
  })

  // Process value
  if (isString(bindings.value)) {
    // Value is a CSS ID or selector
    config.element = bindings.value
  } else if (isNumber(bindings.value)) {
    // Value is offset
    config.offset = mathRound(bindings.value)
  } else if (isObject(bindings.value)) {
    // Value is config object
    // Filter the object based on our supported config options
    keys(bindings.value)
      .filter(k => !!BVScrollspy.DefaultType[k])
      .forEach(k => {
        config[k] = bindings.value[k]
      })
  }

  return config
}

(obj, path, defaultValue = undefined) => {
  // Handle array of path values
  path = isArray(path) ? path.join('.') : path

  // If no path or no object passed
  if (!path || !isObject(obj)) {
    return defaultValue
  }

  // Handle edge case where user has dot(s) in top-level item field key
  // See https://github.com/bootstrap-vue/bootstrap-vue/issues/2762
  // Switched to `in` operator vs `hasOwnProperty` to handle obj.prototype getters
  // https://github.com/bootstrap-vue/bootstrap-vue/issues/3463
  if (path in obj) {
    return obj[path]
  }

  // Handle string array notation (numeric indices only)
  path = String(path).replace(RX_ARRAY_NOTATION, '.$1')

  const steps = path.split('.').filter(identity)

  // Handle case where someone passes a string of only dots
  if (steps.length === 0) {
    return defaultValue
  }

  // Traverse path in object to find result
  // Switched to `in` operator vs `hasOwnProperty` to handle obj.prototype getters
  // https://github.com/bootstrap-vue/bootstrap-vue/issues/3463
  return steps.every(step => isObject(obj) && step in obj && !isUndefinedOrNull((obj = obj[step])))
    ? obj
    : isNull(obj)
      ? null
      : defaultValue
}

makeOcRequest(cb, params = {}) {
  // Merge given params with defaults
  params = { ...OC_DEFAULT_PARAMS, ...params }
  // Build the query
  const query = Object.keys(params).reduce(
    (query, key) => (params[key] ? `${query}${query ? '&' : ''}${key}=${params[key]}` : query),
    ''
  )

  const url = `${OC_BASE_URL}?${query}`
  const xhr = new XMLHttpRequest()

  const onLoad = () => {
    if (xhr.readyState !== 4) {
      return
    }
    if (xhr.status === 200) {
      const response = JSON.parse(xhr.responseText) || {}
      cb(this.processOcNodes(response.nodes || []), null)
    } else {
      // We just return an empty node list rather than spew an error
      // eslint-disable-next-line node/no-callback-literal
      cb([], xhr.statusText)
    }
  }

  xhr.open('GET', url, true)
  xhr.addEventListener('load', onLoad, {
    signal: this.controller ? this.controller.signal : undefined
  })
  // Initiate the request
  xhr.send()
}

(file, data) =>
  new Promise((resolve, reject) => {
    file = path.join(bootstrapIconsDir, file)
    if (path.extname(file) !== '.svg') {
      resolve()
      return
    }
    const name = pascalCase(path.basename(file, '.svg'))
    const componentName = `BIcon${name}`

    fs.readFile(file, 'utf8')
      .then(svg => {
        const content = svg
          // Remove <svg ...> and </svg>
          .replace(/<svg[^>]+>/i, '')
          .replace(/<\/svg>/i, '')
          // Remove whitespace between elements
          .replace(/>\s+</g, '><')
          // Fix broken stroke colors in some components
          // Might be fixed in 1.0.0-alpha3 release
          .replace(' stroke="#000"', ' stroke="currentColor"')
          // Remove leading/trailing whitespace
          .trim()
        // Add to the iconsData object
        data.icons[componentName] = { name, content }
        data.componentNames.push(componentName)
        // Resolve
        resolve()
      })
      .catch(error => reject(error))
  })

render(h, { props, data, slots, scopedSlots }) {
  const { id, variant, header, headerTag } = props
  const $slots = slots()
  const $scopedSlots = scopedSlots || {}
  const slotScope = {}
  const headerId = id ? `_bv_${id}_group_dd_header` : null

  let $header = h()
  if (hasNormalizedSlot(SLOT_NAME_HEADER, $scopedSlots, $slots) || header) {
    $header = h(
      headerTag,
      {
        staticClass: 'dropdown-header',
        class: [props.headerClasses, { [`text-${variant}`]: variant }],
        attrs: {
          id: headerId,
          role: isTag(headerTag, 'header') ? null : 'heading'
        }
      },
      normalizeSlot(SLOT_NAME_HEADER, slotScope, $scopedSlots, $slots) || header
    )
  }

  return h('li', mergeData(omit(data, ['attrs']), { attrs: { role: 'presentation' } }), [
    $header,
    h(
      'ul',
      {
        staticClass: 'list-unstyled',
        attrs: {
          ...(data.attrs || {}),
          id,
          role: 'group',
          'aria-describedby':
            [headerId, props.ariaDescribedBy]
              .filter(identity)
              .join(' ')
              .trim() || null
        }
      },
      normalizeSlot(SLOT_NAME_DEFAULT, slotScope, $scopedSlots, $slots)
    )
  ])
}

render(h) {
  const { title, tag, variant, pill, disabled } = this
  const tagId = this.safeId()
  const tagLabelId = this.safeId('_taglabel_')

  let $remove = h()
  if (!this.noRemove && !disabled) {
    $remove = h(BButtonClose, {
      staticClass: 'b-form-tag-remove',
      props: { ariaLabel: this.removeLabel },
      attrs: {
        'aria-controls': tagId,
        'aria-describedby': tagLabelId,
        'aria-keyshortcuts': 'Delete'
      },
      on: {
        click: this.onRemove,
        keydown: this.onRemove
      }
    })
  }

  const $tag = h(
    'span',
    {
      staticClass: 'b-form-tag-content flex-grow-1 text-truncate',
      attrs: { id: tagLabelId }
    },
    this.normalizeSlot() || title
  )

  return h(
    BBadge,
    {
      staticClass: 'b-form-tag d-inline-flex align-items-baseline mw-100',
      class: { disabled },
      props: {
        tag,
        variant,
        pill
      },
      attrs: {
        id: tagId,
        title: title || null,
        'aria-labelledby': tagLabelId
      }
    },
    [$tag, $remove]
  )
}

render(h, { props, data, slots, scopedSlots }) {
  const { prepend, prependHtml, append, appendHtml, size } = props
  const $scopedSlots = scopedSlots || {}
  const $slots = slots()
  const slotScope = {}

  let $prepend = h()
  const hasPrependSlot = hasNormalizedSlot(SLOT_NAME_PREPEND, $scopedSlots, $slots)
  if (hasPrependSlot || prepend || prependHtml) {
    $prepend = h(BInputGroupPrepend, [
      hasPrependSlot
        ? normalizeSlot(SLOT_NAME_PREPEND, slotScope, $scopedSlots, $slots)
        : h(BInputGroupText, { domProps: htmlOrText(prependHtml, prepend) })
    ])
  }

  let $append = h()
  const hasAppendSlot = hasNormalizedSlot(SLOT_NAME_APPEND, $scopedSlots, $slots)
  if (hasAppendSlot || append || appendHtml) {
    $append = h(BInputGroupAppend, [
      hasAppendSlot
        ? normalizeSlot(SLOT_NAME_APPEND, slotScope, $scopedSlots, $slots)
        : h(BInputGroupText, { domProps: htmlOrText(appendHtml, append) })
    ])
  }

  return h(
    props.tag,
    mergeData(data, {
      staticClass: 'input-group',
      class: { [`input-group-${size}`]: size },
      attrs: {
        id: props.id || null,
        role: 'group'
      }
    }),
    [$prepend, normalizeSlot(SLOT_NAME_DEFAULT, slotScope, $scopedSlots, $slots), $append]
  )
}

async () => {
  if (!props.fullFile || isLoading.value) return

  isLoading.value = true

  try {
    // Dynamically import StackBlitz SDK
    const { default: sdk } = await import('@stackblitz/sdk')

    // Create a complete Vue project with BootstrapVueNext using node template
    // This gives us full control over the file structure
    const project = {
      title: props.title || 'BootstrapVueNext Example',
      description: 'Example from BootstrapVueNext documentation',
      template: 'node' as const,
      files: createProjectFiles(),
    }

    // Open the project in a new tab
    await sdk.openProject(project, {
      newWindow: true,
      openFile: 'src/components/Comp.vue',
    })
  } catch (error) {
    console.error('Failed to open StackBlitz project:', error)
    // Fallback to basic StackBlitz
    window.open('https://stackblitz.com/fork/vue-ts', '_blank')
  } finally {
    // Reset loading state after a short delay to show completion
    setTimeout(() => {
      isLoading.value = false
    }, 500)
  }
}

() => {
  const fmOverride = frontmatter.value?.migrationGuide
  if (fmOverride === false) return null
  if (typeof fmOverride === 'string' && fmOverride) {
    return withBase(`/docs/migration-guide#${fmOverride}`)
  }

  const base = inferredBase.value
  if (!base || !page.value?.relativePath) return null

  const segments = page.value.relativePath.split('/')
  const filename = segments[segments.length - 1]?.replace(/\.md$/i, '')
  if (!filename) return null

  // Skip partials (prefixed with _)
  if (filename.startsWith('_')) return null

  let anchor: string | null = null

  if (base === 'githubComponentsDirectory') {
    // Derive: kebab → PascalCase → prepend B → lowercase
    anchor = `b${toPascalCase(filename)}`.toLowerCase()
  } else if (base === 'githubDirectivesDirectory') {
    // Normalize: handle both kebab-case (b-toggle) and PascalCase (BToggle)
    // Strip b-/B prefix, remove hyphens, lowercase
    const name = filename.startsWith('b-')
      ? filename.slice(2).replace(/-/g, '')
      : filename.startsWith('B')
        ? filename.slice(1)
        : filename
    anchor = name.toLowerCase()
  }

  return anchor ? withBase(`/docs/migration-guide#${anchor}`) : null
}

