(event: Readonly<Event>, stepper: (step: number) => void) => {
  const {type} = event || {}

  if (!props.disabled && !props.readonly) {
    if (isMouseEvent(event)) {
      // We only respond to left (main === 0) button clicks
      if (type === 'mousedown' && event.button) return
    }
    resetTimers()
    // Step the counter initially
    stepper(1)
    const threshold = computedThreshold.value
    const multiplier = computedStepMultiplier.value
    const delay = computedDelay.value
    const interval = computedInterval.value

    // Initiate the delay/repeat interval
    $_autoDelayTimer = setTimeout(() => {
      let count = 0
      $_autoRepeatTimer = setInterval(() => {
        // After N initial repeats, we increase the incrementing step amount
        // We do this to minimize screen reader announcements of the value
        // (values are announced every change, which can be chatty for SR users)
        // And to make it easer to select a value when the range is large
        stepper(count < threshold ? 1 : multiplier)
        count++
      }, interval)
    }, delay)
  }
}

(
  defaults: BAppProps['defaults'] | Ref<BAppProps['defaults']>,
  mergeDefaults: BAppProps['mergeDefaults']
) => {
  // Inject existing defaults from parent (could be from plugins)
  const injectedDefaults = inject(defaultsKey, null)

  // Merge injected defaults with prop defaults (prop takes priority)
  const mergedDefaults = computed<Partial<BvnComponentProps>>(() => {
    const _defaults = unref(defaults)
    if (!injectedDefaults) {
      return _defaults ?? {}
    }
    const merged = {...injectedDefaults.value} as Partial<BvnComponentProps>

    if (_defaults) {
      // If mergeDefaults is a function, call it with
      if (mergeDefaults) {
        if (typeof mergeDefaults === 'function') {
          return mergeDefaults(merged, _defaults) as Partial<BvnComponentProps>
        } else if (mergeDefaults === true) {
          return deepMerge(merged, _defaults)
        }
        return Object.assign(merged, _defaults)
      }
      return _defaults
    }

    return merged
  })

  // Provide the merged defaults to child components
  provide(defaultsKey, mergedDefaults)
}

(el: ElementWithScrollspy, binding: Readonly<DirectiveBinding>) => {
  // SSR guard: skip on server
  const doc = getSafeDocument()
  if (doc === null) return

  const uid = getDirectiveUid(binding)

  // Initialize UID namespace for this directive
  const elWithScrollspy = el as ElementWithScrollspy & Record<string, unknown>
  elWithScrollspy.$__scrollspy = elWithScrollspy.$__scrollspy ?? Object.create(null)

  // Clean up existing instance if present
  const existingInstance = elWithScrollspy.$__scrollspy![uid]
  if (existingInstance) {
    existingInstance.cleanup()
  }

  const {arg, value} = binding
  const isObject = typeof value === 'object' && value !== null
  const content = arg
    ? arg
    : typeof value === 'string'
      ? value
      : isObject
        ? value.content || value.element
        : null

  // Store scrollspy instance for this component instance
  elWithScrollspy.$__scrollspy![uid] = useScrollspy(
    content,
    el,
    isObject ? omit(value, ['content', 'element']) : {}
  )
}

(newValue, oldValue) => {
  if (areEqual(newValue, oldValue)) return
  if (index.value === undefined) {
    modelValue.value = undefined
    return
  }

  if (!props.free) {
    const idx = !isReadOnlyArray(index.value) ? index.value : index.value?.[0]
    if (idx !== undefined && accordionItems.value[idx]?.id) {
      if (modelValue.value !== accordionItems.value[idx]?.id) {
        modelValue.value = accordionItems.value[idx]?.id
      }
    } else {
      nextTick(() => {
        index.value = undefined
      })
    }
  } else {
    // free mode
    if (isReadOnlyArray(index.value)) {
      const newValue = index.value
        .map((item) => accordionItems.value[item]?.id)
        .filter((el) => el !== undefined)
      if (!areEqual(newValue, modelValue.value)) {
        modelValue.value = newValue
      }
    } else {
      const newValue = accordionItems.value[index.value]?.id
      if (newValue === undefined) {
        nextTick(() => {
          index.value = undefined
        })
        return
      }
      if (!areEqual(newValue, modelValue.value)) {
        modelValue.value = newValue
      }
    }
  }
}

() => {
  const {value} = computedModelValue

  const els = elements.value.map((p) => {
    switch (p) {
      case FIRST_BUTTON:
        return {id: p, ...firstButtonProps.value}
      case PREV_BUTTON:
        return {id: p, ...prevButtonProps.value}
      case NEXT_BUTTON:
        return {id: p, ...nextButtonProps.value}
      case LAST_BUTTON:
        return {id: p, ...lastButtonProps.value}
      case FIRST_ELLIPSIS:
      case LAST_ELLIPSIS:
        return {id: p, ...ellipsisProps.value}
      default:
        return {id: p, ...getPageButtonProps(p)}
    }
  })

  if (numberOfPages.value > 3) {
    if (value > numberOfPages.value - halfLimit.value - lastPage.value) {
      const idx = 2 + showFirstButton.value
      const el = els[idx]
      if (el !== undefined) {
        els[idx] = {id: el.id, ...getPageButtonProps(el.id, true)}
      }
    }

    if (value <= halfLimit.value + firstPage.value) {
      const idx = els.length - (3 + showLastButton.value)
      const el = els[idx]
      if (el !== undefined) {
        els[idx] = {id: el.id, ...getPageButtonProps(el.id, true)}
      }
    }
  }

  return els
}

beforeUnmount() {
    if (typeof window !== 'undefined') {
        document.removeEventListener('click', this.clickedOutside)
        if (this.dropdownPosition === 'auto') {
            window.removeEventListener(
                'resize',
                this.calcDropdownInViewportVertical
            )
        }
        if (this.appendToBody) {
            window.removeEventListener(
                'scroll',
                this.calcDropdownInViewportVertical
            )
        }
    }
    if (
        this.checkInfiniteScroll &&
        this.$refs.dropdown &&
        (this.$refs.dropdown as Element).querySelector('.dropdown-content')
    ) {
        const list = (this.$refs.dropdown as Element).querySelector(
            '.dropdown-content'
        )!
        list.removeEventListener(
            'scroll',
            this.checkIfReachedTheEndOfScroll
        )
    }
    if (this.appendToBody && this.$data._bodyEl) {
        removeElement(this.$data._bodyEl)
    }
    clearTimeout(this.timeOutID)
}

selectItem(value: ItemValueType) {
    if (this.multiple) {
        if (this.selected) {
            const selected = this.selected as ItemValueType[]
            if (selected.indexOf(value) === -1) {
                // Add value
                this.selected = [...selected, value]
            } else {
                // Remove value
                this.selected = selected.filter((val) => val !== value)
            }
        } else {
            this.selected = [value]
        }
        this.$emit('change', this.selected)
    } else {
        if (this.selected !== value) {
            this.selected = value
            this.$emit('change', this.selected)
        }
    }
    this.$emit('update:modelValue', this.selected)
    if (!this.multiple) {
        this.isActive = !this.closeOnClick
        if (this.hoverable && this.closeOnClick) {
            this.isHoverable = false
        }
    }
}

sort(
    column: ITableColumn | null | undefined,
    updatingData: boolean | null = false,
    event: ModifierKeys | null = null
) {
    if (!column || !column.sortable) return
    if (
        // if backend sorting is enabled, just emit the sort press like usual
        // if the correct key combination isnt pressed, sort like usual
        !this.backendSorting &&
        this.sortMultiple &&
        ((this.sortMultipleKey && event![this.sortMultipleKey]) || !this.sortMultipleKey)
    ) {
        if (updatingData) {
            this.doSortMultiColumn()
        } else {
            this.sortMultiColumn(column)
        }
    } else {
        // sort multiple is enabled but the correct key combination isnt pressed so reset
        if (this.sortMultiple) {
            this.sortMultipleDataLocal = []
        }

        if (!updatingData) {
            this.isAsc = toRaw(column) === toRaw(this.currentSortColumn)
                ? !this.isAsc
                : (this.defaultSortDirection.toLowerCase() !== 'desc')
        }
        if (!this.firstTimeSort) {
            this.$emit('sort', column.field, this.isAsc ? 'asc' : 'desc', event)
        }
        if (!this.backendSorting) {
            this.doSortSingleColumn(column)
        }
        this.currentSortColumn = column
    }
}

computedData(): DataItem[] {
    const { groupField, groupOptions } = this
    if (groupField) {
        if (groupOptions) {
            const newData: DataItem[] = []
            this.data.forEach((option) => {
                const group = getValueByPath(option, groupField)
                const items = getValueByPath(option, groupOptions)
                newData.push({ group, items })
            })
            return newData
        } else {
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const tmp: Record<string, any[]> = {}
            this.data.forEach((option) => {
                const group = getValueByPath(option, groupField)
                if (!tmp[group]) tmp[group] = []
                tmp[group].push(option)
            })
            const newData: DataItem[] = []
            Object.keys(tmp).forEach((group) => {
                newData.push({ group, items: tmp[group] })
            })
            return newData
        }
    }
    return [{ items: this.data }]
}

trackMouse(event: MouseEvent | TouchEvent) {
    if (this.captureMouse === false) {
        return
    }
    event.preventDefault()
    event.stopPropagation()

    const touches = (event as TouchEvent).touches
    let [mouseX, mouseY] = [0, 0]
    if (typeof touches !== 'undefined' && touches.length) {
        [mouseX, mouseY] = [touches[0].clientX, touches[0].clientY]
    } else {
        [mouseX, mouseY] = [(event as MouseEvent).clientX, (event as MouseEvent).clientY]
    }
    const angle = Math.atan2(
        mouseY - this.clientOffset.cy,
        mouseX - this.clientOffset.cx
    )

    if (this.captureType === 'sl') {
        const saturation = (mouseX - this.clientOffset.cx) /
            (this.clientOffset.width - this.thickness * 2) +
            0.5
        const lightness = (mouseY - this.clientOffset.cy) /
            (this.clientOffset.height - this.thickness * 2) +
            0.5

        this.saturation = Math.round(Math.min(1, Math.max(0, saturation)) * 1000) / 1000
        this.lightness = 1 - Math.round(Math.min(1, Math.max(0, lightness)) * 1000) / 1000
    } else {
        this.hue = Math.round(angle / Math.PI * 180 + 90) % 360
    }
    this.emitColor()
}

loadAsyncData() {
    const params = [
        "api_key=bb6f51bef07465653c3e553d6ab161a8",
        "language=en-US",
        "include_adult=false",
        "include_video=false",
        `sort_by=${this.sortField}.${this.sortOrder}`,
        `page=${this.page}`,
    ].join("&");

    this.loading = true;
    this.$http
        .get(`https://api.themoviedb.org/3/discover/movie?${params}`)
        .then(({ data }) => {
            // api.themoviedb.org manage max 1000 pages
            this.data = [];
            let currentTotal = data.total_results;
            if (data.total_results / this.perPage > 1000) {
                currentTotal = this.perPage * 1000;
            }
            this.total = currentTotal;
            data.results.forEach((item: Record) => {
                item.release_date = item.release_date
                    ? item.release_date.replace(/-/g, "/")
                    : null;
                this.data.push(item);
            });
            this.loading = false;
        })
        .catch((error) => {
            this.data = [];
            this.total = 0;
            this.loading = false;
            throw error;
        });
}

handleKeyDown(e) {
  const { target, keyCode } = e;

  switch (keyCode) {
    case KeyCode.up:
      const prev = getSibling(target, -1);
      focusNode(prev);
      break;
    case KeyCode.down:
      const next = getSibling(target, 1);
      focusNode(next);
      break;
    case KeyCode.left:
      const preMenu = this.$refs.menu[getMenuIndex(target) - 1];
      if (preMenu) {
        const expandedNode = preMenu.$el.querySelector('.el-cascader-node[aria-expanded="true"]');
        focusNode(expandedNode);
      }
      break;
    case KeyCode.right:
      const nextMenu = this.$refs.menu[getMenuIndex(target) + 1];
      if (nextMenu) {
        const firstNode = nextMenu.$el.querySelector('.el-cascader-node[tabindex="-1"]');
        focusNode(firstNode);
      }
      break;
    case KeyCode.enter:
      checkNode(target);
      break;
    case KeyCode.esc:
    case KeyCode.tab:
      this.$emit('close');
      break;
    default:
      return;
  }
}
